use std::collections::HashMap;
use std::time::{Duration, Instant};

struct WebhookPayload {
    id: String,
    status: String,
    data: HashMap<String, String>,
}

impl WebhookPayload {
    fn new(id: &str, status: &str, data: HashMap<String, String>) -> Self {
        WebhookPayload {
            id: id.to_string(),
            status: status.to_string(),
            data,
        }
    }
}

fn calculate_backoff(attempt: u32) -> Duration {
    if attempt == 0 {
        return Duration::from_secs(1);
    }
    Duration::from_millis((2u64.pow(attempt) * 100) as u64)
}

fn process_payload(payload: &WebhookPayload, max_retries: u32) -> Result<(), String> {
    let mut attempt = 0;
    while attempt <= max_retries {
        if payload.status != "failed" {
            println!("Successfully processed payload ID: {}", payload.id);
            return Ok(()) 
        }

        if attempt > 0 && attempt <= max_retries {
            let backoff = calculate_backoff(attempt);
            println!("Status is 'failed' for payload ID: {}. Retrying in {:?}...", payload.id, backoff);
            std::thread::sleep(backoff);
        }

        if attempt == max_retries {
            return Err(format!("Failed after {} attempts for payload ID: {}", max_retries + 1, payload.id));
        }
        attempt += 1;
    }
    Ok(()) 
}

fn main() {
    let mut initial_data = HashMap::new();
    initial_data.insert("user_id".to_string(), "abc".to_string());
    let payload_a = WebhookPayload::new("webhook_123", "failed", initial_data.clone());

    let mut data_success = HashMap::new();
    data_success.insert("user_id".to_string(), "xyz".to_string());
    let payload_b = WebhookPayload::new("webhook_456", "success", data_success);

    println!("--- Processing Failing Payload (Retry Expected) ---");
    match process_payload(&payload_a, 2) {
        Ok(_) => (), 
        Err(e) => println!("Error handling payload A: {}", e),
    }

    println!("
--- Processing Successful Payload (No Retry) ---");
    match process_payload(&payload_b, 2) {
        Ok(_) => (), 
        Err(e) => println!("Error handling payload B: {}", e),
    }
}

use std::collections::VecDeque;
use std::mem;

struct MemoryPool { 
    available_slots: VecDeque<u32>,
    total_capacity: usize,
}

impl MemoryPool {
    fn new(capacity: usize) -> Self {
        MemoryPool { 
            available_slots: VecDeque::with_capacity(capacity),
            total_capacity: capacity,
        }
    }

    fn allocate(&mut self) -> Option<u32> {
        self.available_slots.pop_front()
    }

    fn deallocate(&mut self, slot: u32) {
        if self.available_slots.len() < self.total_capacity {
            self.available_slots.push_back(slot);
        }
    }
}

fn main() {
    let mut pool = MemoryPool::new(10);

    pool.deallocate(100); 
    pool.deallocate(200); 

    let slot1 = pool.allocate();
    if let Some(s) = slot1 {
        println!("Allocated first slot: {}", s);
    }

    pool.deallocate(300);
    pool.deallocate(400);

    let slot2 = pool.allocate();
    if let Some(s) = slot2 {
        println!("Allocated second slot: {}", s);
    }
}

use std::mem;

#[repr(C)]
struct BoardPosition {
    file: i32,
    rank: i32,
}

extern "C" fn check_equivalence_backend(pos1: *const BoardPosition, pos2: *const BoardPosition) -> bool {
    if pos1.is_null() || pos2.is_null() {
        return false;
    }
    let p1 = unsafe { &*pos1 };
    let p2 = unsafe { &*pos2 };

    (p1.file == p2.file && p1.rank == p2.rank) || (p1.file == 0 && p1.rank == 0)
}

fn main() {
    let pos_a = BoardPosition { file: 1, rank: 2 };
    let pos_b = BoardPosition { file: 1, rank: 2 };
    let pos_c = BoardPosition { file: 3, rank: 4 };

    let c_pos_a = &pos_a as *const BoardPosition;
    let c_pos_b = &pos_b as *const BoardPosition;
    let c_pos_c = &pos_c as *const BoardPosition;

    let result1 = check_equivalence_backend(c_pos_a, c_pos_b);
    println!("Are A and B equivalent? {}", result1);

    let result2 = check_equivalence_backend(c_pos_a, c_pos_c);
    println!("Are A and C equivalent? {}", result2);
}
